export type INLUSlots = {
    /** Dates found in the text of the user */
    DATE?: IDateSlot[];
    /** Numbers found in the text of the user */
    NUMBER?: number[];
    /** Durations found in the text of the user */
    DURATION?: IDurationSlot[];
    /** Temperate(s) found in the text of the user */
    TEMPERATURE?: number[];
    /** Contains found age */
    AGE?: number[];
    /** Contains found percentage */
    PERCENTAGE?: number[];
    /** Contains all found and valid emails */
    EMAIL?: string[];
} & INLUKeyphrases;
/**
 * The date Slot
 */
export interface IDateSlot {
    start?: {
        day: number;
        hour: number;
        millisecond: number;
        minute: number;
        month: number;
        second: number;
        weekday: number;
        dayOfWeek: string;
        year: number;
    } | null;
    end?: {
        day: number;
        hour: number;
        millisecond: number;
        minute: number;
        month: number;
        second: number;
        weekday: number;
        dayOfWeek: string;
        year: number;
    } | null;
}
/**
 * The duration Slot
 */
export interface IDurationSlot {
    year?: number;
    month?: number;
    week?: number;
    day?: number;
    hour?: number;
    minute?: number;
    second?: number;
}
/**
 * Cognigy keyphrases
 */
export type INLUKeyphrases = Record<string, IMatchedKeyphrase[]>;
export interface IMatchedKeyphrase {
    keyphrase: string;
    synonym: string;
    lower: string;
    count?: number;
    neg?: boolean;
    data?: object;
    offset?: IOffset;
    lexiconId?: string;
    lexiconReferenceId?: string;
}
interface IOffset {
    start: number;
    end: number;
}
export {};
